+        assert!(json.get("crate_path").is_some());
+        assert!(json.get("connector_id").is_some());
+        assert!(json.get("cohort").is_some());
+        assert!(json.get("level").is_some());
+        assert!(json.get("has_manifest").is_some());
+    }
